                                        RoundedRectangle(cornerRadius: 16)
                                            .stroke(
                                                appIconManager.currentIcon == icon ? Color.blue : Color.Theme.border,
                                                lineWidth: appIconManager.currentIcon == icon ? 3 : 1
                                            )
                                    )
                                    .shadow(radius: 2)

